Here are the public test cases for feature1_3_round:
{
  "description": "Round a number to the nearest multiple of a given base (default base 1). The base may be a large integer (rounding to tens, etc.), a small fraction below 1 (rounding to a fixed number of decimals while avoiding floating-point drift), or negative (its magnitude is used). If either the value or the base is the not-a-number sentinel, the result is the not-a-number sentinel.",
  "cases": [
    {
      "input": {
        "op": "round",
        "value": 29847.23,
        "base": 10
      },
      "expected_output": "value=29850"
    },
    {
      "input": {
        "op": "round",
        "value": 0.1234321,
        "base": 0.0001
      },
      "expected_output": "value=0.1234"
    },
    {
      "input": {
        "op": "round",
        "value": 4.2,
        "base": -5
      },
      "expected_output": "value=5"
    },
    {
      "input": {
        "op": "round",
        "value": "NaN",
        "base": 10
      },
      "expected_output": "value=NaN"
    }
  ]
}

Here are the public test cases for feature2_murmur_hash:
{
  "description": "Compute the 128-bit x64 MurmurHash3 of a UTF-16 string and render it as a fixed 32-character lowercase hexadecimal digest. The same input always produces the same digest; an empty string produces all zeros.",
  "cases": [
    {
      "input": {
        "op": "hash",
        "text": "Hello, world"
      },
      "expected_output": "hash=ebd28b45027ab97477416103e3fff7b8"
    },
    {
      "input": {
        "op": "hash",
        "text": ""
      },
      "expected_output": "hash=00000000000000000000000000000000"
    }
  ]
}

Here are the public test cases for feature3_1_collect_error_isolation:
{
  "description": "Collect a set of named data sources into a components map. Each source is invoked independently: a source that returns a value is recorded as a value component, while a source that throws is caught and recorded as an error component whose normalized message carries the source's error text. One failing source never aborts the others, and the collection preserves the original source order.",
  "cases": [
    {
      "input": {
        "op": "collect",
        "sources": [
          {
            "name": "success1",
            "returns": "foo"
          },
          {
            "name": "throwsErrorObject",
            "throws": "bar",
            "as": "error"
          },
          {
            "name": "throwsErrorString",
            "throws": "baz",
            "as": "string"
          },
          {
            "name": "success2",
            "returns": "baq"
          }
        ]
      },
      "expected_output": "name=success1 outcome=value value=\"foo\"\nname=throwsErrorObject outcome=error message=bar\nname=throwsErrorString outcome=error message=baz\nname=success2 outcome=value value=\"baq\""
    }
  ]
}

Here are the public test cases for feature3_2_collect_exclusion:
{
  "description": "Collect named data sources while skipping any source listed in the exclusion set. Excluded sources are neither invoked nor present in the resulting components map; only the surviving sources, in their original order, are collected.",
  "cases": [
    {
      "input": {
        "op": "collect",
        "sources": [
          {
            "name": "toBe",
            "returns": true
          },
          {
            "name": "notToBe",
            "returns": false
          }
        ],
        "exclude": [
          "notToBe"
        ]
      },
      "expected_output": "name=toBe outcome=value value=true"
    }
  ]
}

Here are the public test cases for feature4_1_screen_frame:
{
  "description": "Compute the screen 'frame' (the gap on each side between the full screen and the available screen area) as a four-element list ordered top, right, bottom, left. Top equals availTop; right equals width - availWidth - availLeft; bottom equals height - availHeight - availTop; left equals availLeft. When availLeft/availTop are unavailable they are treated as 0 for the width/height arithmetic but reported as the null sentinel in their own positions. A frame whose sides are all zero is reported as all zeros. The rounded form snaps each non-null side to the nearest multiple of 10.",
  "cases": [
    {
      "input": {
        "op": "screen_frame",
        "screen": {
          "width": 1440,
          "height": 900,
          "availWidth": 1367,
          "availHeight": 853,
          "availLeft": 49,
          "availTop": 11
        }
      },
      "expected_output": "frame=[11,24,36,49]\nrounded=[10,20,40,50]"
    },
    {
      "input": {
        "op": "screen_frame",
        "screen": {
          "width": 1280,
          "height": 1024,
          "availWidth": 1182,
          "availHeight": 1000,
          "availLeft": null,
          "availTop": null
        }
      },
      "expected_output": "frame=[null,98,24,null]\nrounded=[null,100,20,null]"
    }
  ]
}

Here are the public test cases for feature4_2_screen_frame_watch:
{
  "description": "Watch the screen frame over time to mitigate the fact that the frame momentarily collapses to all-zero in some conditions. A 'watch' step starts monitoring; each 'tick' re-samples the current screen geometry; each 'get' reports the frame that would be exposed. Behavior: while the live frame is all-zero and no non-zero frame has ever been observed, get reports all zeros. Once any non-zero frame is observed it is remembered, and a later get that finds the live frame collapsed to all-zero returns the remembered non-zero frame instead. When the live frame is itself non-zero, get returns the live frame and updates the remembered value.",
  "cases": [
    {
      "input": {
        "op": "screen_frame_watch",
        "steps": [
          {
            "set": {
              "width": 640,
              "height": 480,
              "availWidth": 640,
              "availHeight": 480,
              "availLeft": 0,
              "availTop": 0
            },
            "do": "watch"
          },
          {
            "do": "get"
          },
          {
            "set": {
              "width": 640,
              "height": 480,
              "availWidth": 600,
              "availHeight": 400,
              "availLeft": 10,
              "availTop": 30
            },
            "do": "tick"
          },
          {
            "set": {
              "width": 640,
              "height": 480,
              "availWidth": 640,
              "availHeight": 480,
              "availLeft": 0,
              "availTop": 0
            },
            "do": "tick"
          },
          {
            "do": "get"
          },
          {
            "set": {
              "width": 640,
              "height": 480,
              "availWidth": 600,
              "availHeight": 400,
              "availLeft": 30,
              "availTop": 10
            },
            "do": "tick"
          },
          {
            "do": "get"
          },
          {
            "set": {
              "width": 640,
              "height": 480,
              "availWidth": 640,
              "availHeight": 480,
              "availLeft": 0,
              "availTop": 0
            },
            "do": "tick"
          },
          {
            "do": "get"
          }
        ]
      },
      "expected_output": "frame=[0,0,0,0]\nframe=[30,30,50,10]\nframe=[10,10,70,30]\nframe=[10,10,70,30]"
    }
  ]
}

